import{_ as a,o as s,c as o,a2 as e}from"./chunks/framework.DS_HIvHc.js";const h=JSON.parse('{"title":"처음 시작하기","description":"","frontmatter":{},"headers":[],"relativePath":"guide/first-steps.md","filePath":"guide/first-steps.md","lastUpdated":1773710852000}'),r={name:"guide/first-steps.md"};function n(d,t,l,i,c,p){return s(),o("div",null,[...t[0]||(t[0]=[e(`<h1 id="처음-시작하기" tabindex="-1">처음 시작하기 <a class="header-anchor" href="#처음-시작하기" aria-label="Permalink to &quot;처음 시작하기&quot;">​</a></h1><blockquote><p>5분이면 Cowork를 시작할 수 있습니다. 차근차근 따라해보세요.</p></blockquote><h2 id="_1-claude-desktop-다운로드" tabindex="-1">1. Claude Desktop 다운로드 <a class="header-anchor" href="#_1-claude-desktop-다운로드" aria-label="Permalink to &quot;1. Claude Desktop 다운로드&quot;">​</a></h2><p><a href="https://claude.ai/download" target="_blank" rel="noreferrer">claude.ai/download</a>에서 내 컴퓨터(Windows 또는 Mac)에 맞는 버전을 다운로드합니다.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>일반 프로그램 설치와 동일합니다. 다운로드 → 실행 → 다음 → 완료!</p></div><h2 id="_2-로그인하기" tabindex="-1">2. 로그인하기 <a class="header-anchor" href="#_2-로그인하기" aria-label="Permalink to &quot;2. 로그인하기&quot;">​</a></h2><p>Claude Desktop을 실행하면 로그인 화면이 나옵니다. 회사에서 계정을 발급받았다면 해당 계정으로, 아니면 개인 계정으로 로그인하세요.</p><h2 id="_3-cowork-모드-켜기" tabindex="-1">3. Cowork 모드 켜기 <a class="header-anchor" href="#_3-cowork-모드-켜기" aria-label="Permalink to &quot;3. Cowork 모드 켜기&quot;">​</a></h2><p>로그인 후 화면 상단 또는 설정에서 <strong>&quot;Cowork&quot;</strong> 모드를 활성화합니다. 이제 Claude가 내 컴퓨터의 파일을 보고, 직접 도와줄 수 있게 됩니다.</p><div class="warning custom-block"><p class="custom-block-title">파일 접근 권한</p><p>처음 켜면 &quot;파일 접근을 허용할까요?&quot;라고 물어봅니다. <strong>허용</strong>해야 Cowork 기능을 쓸 수 있어요. 걱정 마세요 — 허용한 폴더의 파일만 봅니다.</p></div><h2 id="_4-작업-폴더-선택" tabindex="-1">4. 작업 폴더 선택 <a class="header-anchor" href="#_4-작업-폴더-선택" aria-label="Permalink to &quot;4. 작업 폴더 선택&quot;">​</a></h2><p>Claude가 접근할 폴더를 선택합니다. 보통 <strong>내 문서</strong> 폴더나, 현재 작업 중인 <strong>프로젝트 폴더</strong>를 선택하면 됩니다.</p><h2 id="화면-구성-알아보기" tabindex="-1">화면 구성 알아보기 <a class="header-anchor" href="#화면-구성-알아보기" aria-label="Permalink to &quot;화면 구성 알아보기&quot;">​</a></h2><table tabindex="0"><thead><tr><th>영역</th><th>설명</th></tr></thead><tbody><tr><td><strong>대화 영역</strong></td><td>Claude와 대화하는 공간. 평소 메신저 쓰듯이 질문하거나 부탁하면 됩니다.</td></tr><tr><td><strong>파일 패널</strong></td><td>현재 작업 폴더의 파일 목록. Claude가 이 파일들을 읽고 수정할 수 있습니다.</td></tr><tr><td><strong>도구 모음</strong></td><td>파일 첨부, 스크린샷, 설정 등 추가 기능 버튼들이 모여 있습니다.</td></tr><tr><td><strong>설정</strong></td><td>언어, 응답 스타일, 접근 폴더 등을 변경할 수 있습니다.</td></tr></tbody></table><h2 id="_5-custom-instructions-설정하기-선택" tabindex="-1">5. Custom Instructions 설정하기 (선택) <a class="header-anchor" href="#_5-custom-instructions-설정하기-선택" aria-label="Permalink to &quot;5. Custom Instructions 설정하기 (선택)&quot;">​</a></h2><p>처음부터 설정하면 편리합니다. 설정 → Custom Instructions에서 아래 내용을 입력해보세요:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 나는 [이름]이고 [회사명] [부서]에서 일합니다</span></span>
<span class="line"><span>- 보고서는 존댓말, 표 포함, 간결하게 작성해주세요</span></span>
<span class="line"><span>- 이메일은 항상 제목을 함께 제안해주세요</span></span>
<span class="line"><span>- 한국어로 답변해주세요</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>나중에 언제든 수정할 수 있으니 부담 없이 시작하세요!</p></div><div class="tip custom-block"><p class="custom-block-title">준비 완료!</p><p>여기까지 했으면 Cowork를 사용할 준비가 끝났습니다. 다음 섹션에서 첫 대화를 시작해봅시다!</p></div>`,19)])])}const k=a(r,[["render",n]]);export{h as __pageData,k as default};
